mapper.sql:
a.deleted_at IS NULL

    AND (
        a.name LIKE CONCAT('%', #{query.keyword}, '%')
        OR a.app_key LIKE CONCAT('%', #{query.keyword}, '%')
        OR a.summary LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND a.category_id = #{query.categoryId}


    AND a.developer_id = #{query.developerId}


    AND a.status = #{query.status}


    AND a.is_official = #{query.isOfficial}


    AND a.is_featured = #{query.isFeatured}

mapper.select:
SELECT COUNT(1)
FROM tags
WHERE id = #{tagId}

SELECT COUNT(1)
FROM app_versions
WHERE app_id = #{appId}
  AND version_code = #{versionCode}
  AND deleted_at IS NULL

SELECT COUNT(1)
FROM app_packages
WHERE version_id = #{versionId}
  AND os_type = #{osType}
  AND arch = #{arch}
  AND package_format = #{packageFormat}
  AND deleted_at IS NULL
